var areNumbersAscending = function(s) {
    let prev = -1;
    for (const tok of s.split(' ')) {
        if (/^[0-9]+$/.test(tok)) {
            const num = parseInt(tok, 10);
            if (num <= prev) return false;
            prev = num;
        }
    }
    return true;
};
